81	/// LuaTable — array+hash entries plus optional metatable.
82	///
83	/// Weak-table semantics (Phase D-2):
84	///   * `__mode = "v"` — values are weak; mark keys only. Dead values get
85	///     pruned in the post-mark hook via [`crate::value::LuaTable::prune_weak_dead`].
86	///   * `__mode = "kv"` — both sides weak; trace neither. Both get pruned.
87	///   * `__mode = "k"` — keys are weak; trace NEITHER initially. The
88	///     post-mark ephemeron convergence pass walks each weak-key table's
89	///     entries and marks values only for entries whose keys are
90	///     independently reachable. Iterating to fixed point makes
91	///     reachability of value_i transitively depend on key_i — that's the
92	///     defining property of ephemerons.
93	///   * No `__mode` — trace both unconditionally.
94	impl Trace for LuaTable {
95	    fn trace(&self, m: &mut Marker) {
96	        const WEAK_KEYS: u8 = 1;
97	        const WEAK_VALUES: u8 = 1 << 1;
98	        let mode = self.weak_mode();
99	        let trace_keys = (mode & WEAK_KEYS) == 0;
100	        let trace_values = (mode & WEAK_VALUES) == 0 && trace_keys;
101	        let mut key = LuaValue::Nil;
102	        while let Some((k, v)) = self.next_pair(&key) {
103	            if trace_keys {
104	                k.trace(m);
105	            }
106	            if trace_values {
107	                v.trace(m);
108	            }
109	            key = k;
110	        }
111	        if let Some(mt) = self.metatable() {
112	            mt.trace(m);
113	        }
114	    }
115	}
