268	            if matches!(v, LuaValue::Nil) {
269	                return true;
270	            }
271	            if weak_v && !value_is_reachable(v, is_reachable) {
272	                return false;
273	            }
274	            if weak_k && !value_is_reachable(k, is_reachable) {
