pub fn len(state: &mut LuaState, idx: i32) -> Result<(), LuaError> {
    // C: t = index2value(L, idx); luaV_objlen(L, L->top.p, t);
    let t = index_to_value(state, idx);
    let result = state.obj_len(&t)?;
    state.push(result);
    Ok(())

