    fn metatable(&self) -> Option<GcRef<LuaTable>> { (**self).metatable() }
    fn as_ptr(&self) -> *const () { GcRef::identity(self) as *const () }
    fn get(&self, k: &LuaValue) -> LuaValue { (**self).get(k) }
